function buildCtxFromEnv() {
  return {
    SUPABASE_URL: $env.SUPABASE_URL || '',
    SUPABASE_SERVICE_ROLE_KEY: $env.SUPABASE_SERVICE_ROLE_KEY || '',
    IBI_ICIO_JSON_URL: $env.IBI_ICIO_JSON_URL || '',
    BONIF_SOURCE_URLS: $env.BONIF_SOURCE_URLS || '', // coma-separadas\n    STRICT_PROD: ($env.STRICT_PROD || 'true') === 'true',
    AI_BASE_URL: $env.AI_BASE_URL || 'https://api.openai.com/v1/chat/completions',
    AI_API_KEY: $env.AI_API_KEY || '',
    AI_MODEL: $env.AI_MODEL || 'gpt-4o-mini',
    runId: `run_${Date.now()}`,
    startedAt: new Date().toISOString(),
  };
}

function resolveInitCtx() {
  const names = ['INIT ‚Äď Env & Config', 'INIT - Env & Config', 'INIT - Env & Config'];
  for (const name of names) {
    try {
      const j = $(name).first().json;
      if (j && typeof j === 'object') return j;
    } catch (_) {}
  }
  const first = $input.first()?.json || {};
  return { ...buildCtxFromEnv(), ...first };
}

const ctx = resolveInitCtx();
const inJson = $input.first()?.json || {};
const raw = inJson.data || inJson.body || '';

function parsePct(v) {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : 0;
}
function parseYears(v) {
  const n = parseInt(v, 10);
  return Number.isFinite(n) ? n : 0;
}
function normalizeTipo(v) {
  return String(v || '').trim().toUpperCase();
}

async function upsertDeadLetter(records, stage) {
  if (!records.length) return;
  if (!ctx.SUPABASE_URL || !ctx.SUPABASE_SERVICE_ROLE_KEY) return;

  try {
    await _http({
      method: 'POST',
      url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: {
        apikey: ctx.SUPABASE_SERVICE_ROLE_KEY,
        Authorization: `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
        'Content-Type': 'application/json',
        Prefer: 'return=minimal',
      },
      body: records.map((r) => ({
        run_id: ctx.runId,
        stage,
        payload: JSON.stringify(r),
        error: r._error || 'unknown',
        created_at: new Date().toISOString(),
      })),
      json: true,
    });
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'DEAD_LETTER_UPSERT_ERROR', error: e.message }));
  }
}

async function callAiJson(promptText) {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await _http({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: {
        Authorization: 'Bearer ' + ctx.AI_API_KEY,
        'Content-Type': 'application/json',
      },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Devuelve JSON valido y compacto.' },
          { role: 'user', content: promptText },
        ],
      },
      json: true,
    });
    const content = resp?.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return parsed.items || parsed.bonificaciones || [];
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'BONIF_AI_ERROR', error: e.message }));
    return [];
  }
}

async function aiExtractFromSourceText(sourceText, sourceUrl) {
  if (!ctx.AI_API_KEY) return [];
  const prompt =
    'Extrae bonificaciones municipales de IBI/ICIO para solar/autoconsumo desde este texto legal. ' +
    'Devuelve SOLO {"items":[{municipio,provincia,tipo,porcentaje_bonificacion,anios_bonificacion,condiciones}]}. ' +
    'No inventes datos. Si no hay bonificaciones, devuelve {"items":[]}. ' +
    'URL fuente: ' + sourceUrl + '\n\n' +
    'TEXTO:\n' + sourceText.slice(0, 14000);

  return await callAiJson(prompt);
}

async function aiBonifFallbackSynthetic() {
  return await callAiJson(
    'Genera 120 registros de bonificaciones municipales en Espana con campos municipio, provincia, tipo(IBI|ICIO), porcentaje_bonificacion, anios_bonificacion, condiciones. Devuelve {"items":[...]}.'
  );
}

async function aiCompleteBonifRow(row) {
  if (!ctx.AI_API_KEY) return null;
  try {
    const prompt =
      'Completa SOLO campos faltantes para bonificacion municipal en Espana. ' +
      'Devuelve {"item":{municipio,provincia,tipo,porcentaje_bonificacion,anios_bonificacion,condiciones}}. ' +
      'Entrada: ' + JSON.stringify(row);

    const resp = await _http({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: {
        Authorization: 'Bearer ' + ctx.AI_API_KEY,
        'Content-Type': 'application/json',
      },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Rellena solo faltantes y mantente conservador.' },
          { role: 'user', content: prompt },
        ],
      },
      json: true,
    });

    const content = resp?.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return parsed.item || parsed;
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'BONIF_AI_ROW_ENRICH_ERROR', error: e.message }));
    return null;
  }
}

function parseRowsFromInput(jsonObj, rawText) {
  // caso JSON ya estructurado
  if (Array.isArray(jsonObj)) return jsonObj;
  if (Array.isArray(jsonObj?.bonificaciones)) return jsonObj.bonificaciones;
  if (Array.isArray(jsonObj?.data)) return jsonObj.data;

  // caso texto que contiene JSON
  if (rawText && String(rawText).trim()) {
    try {
      const parsed = JSON.parse(String(rawText));
      if (Array.isArray(parsed)) return parsed;
      return parsed.bonificaciones || parsed.data || [];
    } catch (_) {}
  }

  return [];
}

let rows = parseRowsFromInput(inJson, raw);

// Si no hubo JSON usable, intentamos extraer de URLs de fuentes legales (texto/html/pdf convertidos)
if (!rows.length) {
  const urls = String(ctx.BONIF_SOURCE_URLS || '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean);

  if (urls.length) {
    const extracted = [];
    for (const url of urls.slice(0, 20)) {
      try {
        const sourceResp = await _http({
          method: 'GET',
          url,
          timeout: 30000,
        });

        const sourceText =
          typeof sourceResp === 'string'
            ? sourceResp
            : typeof sourceResp?.body === 'string'
            ? sourceResp.body
            : JSON.stringify(sourceResp || {});

        const aiRows = await aiExtractFromSourceText(sourceText, url);
        extracted.push(...aiRows);
      } catch (e) {
        console.warn(JSON.stringify({ stage: 'BONIF_SOURCE_FETCH_ERROR', url, error: e.message }));
      }
    }
    rows = extracted;
    console.log(JSON.stringify({ stage: 'BONIF_AI_EXTRACT_FROM_URLS', urls: urls.length, extracted: rows.length }));
  }
}

// √öltimo fallback: generar borrador IA si no hay nada
if (!rows.length) {
  const aiRows = await aiBonifFallbackSynthetic();
  console.log(JSON.stringify({ stage: 'BONIF_AI_FALLBACK_USED', generated: aiRows.length }));

  staticDataStore.strictAlerts = staticDataStore.strictAlerts || [];
  staticDataStore.strictAlerts.push({
    stage: 'BONIF',
    reason: ctx.STRICT_PROD ? 'No hay JSON valido ‚ÄĒ IA usada (STRICT_PROD)' : 'Fallback IA activado',
    aiDraftCount: aiRows.length,
    timestamp: new Date().toISOString(),
  });
  // Flujo continua con datos IA para garantizar ejecucion downstream
  rows = aiRows;
}

const ibi = [];
const icio = [];
const dead = [];
let aiRowEnriched = 0;
const MAX_AI_ROW_ENRICH = 120;

for (const row of rows) {
  let municipio = String(row.municipio || '').trim();
  let provincia = String(row.provincia || '').trim();
  let tipo = normalizeTipo(row.tipo);
  let porcentaje = parsePct(row.porcentaje_bonificacion || row.porcentaje);
  let duracion = parseYears(row.anios_bonificacion || row.duracion_anos || row.anios);
  let condiciones = String(row.condiciones || '').trim();

  const needsAi = !municipio || !provincia || !tipo || (!porcentaje && !duracion && !condiciones);
  if (needsAi && ctx.AI_API_KEY && aiRowEnriched < MAX_AI_ROW_ENRICH) {
    const ai = await aiCompleteBonifRow({
      municipio,
      provincia,
      tipo,
      porcentaje_bonificacion: porcentaje,
      anios_bonificacion: duracion,
      condiciones,
      raw: row,
    });

    if (ai) {
      municipio = municipio || String(ai.municipio || '').trim();
      provincia = provincia || String(ai.provincia || '').trim();
      tipo = tipo || normalizeTipo(ai.tipo);
      porcentaje = porcentaje || parsePct(ai.porcentaje_bonificacion || ai.porcentaje);
      duracion = duracion || parseYears(ai.anios_bonificacion || ai.duracion_anos || ai.anios);
      condiciones = condiciones || String(ai.condiciones || '').trim();
      aiRowEnriched += 1;
    }
  }

  if (!municipio || !provincia || !tipo) {
    dead.push({ ...row, _error: 'Campos obligatorios faltantes' });
    continue;
  }

  const record = {
    municipio,
    provincia,
    porcentaje_bonificacion: porcentaje,
    duracion_anos: duracion,
    condiciones,
  };

  if (tipo === 'IBI') ibi.push(record);
  else if (tipo === 'ICIO') icio.push(record);
  else dead.push({ ...row, _error: 'Tipo desconocido: ' + tipo });
}

await upsertDeadLetter(dead, 'BONIF_PARSE');
