function toBool(v) {
  const s = String(v || '').trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'si' || s === 'yes';
}

async function aiCompatFallback() {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await _http({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Devuelve JSON valido.' },
          { role: 'user', content: 'Genera 60 combinaciones de compatibilidad con campos inversor, bateria, cargador_ev, compatible(boolean). Devuelve {"items":[...]}.' }
        ]
      },
      json: true
    });
    const content = resp.choices?.[0]?.message?.content || '{}';
    return JSON.parse(content).items || [];
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'COMPAT_AI_FALLBACK_ERROR', error: e.message }));
    return [];
  }
}

async function aiCompleteCompatRow(row) {
  if (!ctx.AI_API_KEY) return null;
  try {
    const prompt = 'Completa SOLO campos faltantes para compatibilidad de equipos solares. Devuelve {"item":{inversor,bateria,cargador_ev,compatible}}. Entrada: ' + JSON.stringify(row);
    const resp = await _http({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Rellena solo faltantes y evita inventar marcas no presentes.' },
          { role: 'user', content: prompt }
        ]
      },
      json: true
    });
    const content = resp.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return parsed.item || parsed;
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'COMPAT_AI_ROW_ENRICH_ERROR', error: e.message }));
    return null;
  }
}

let records = [];
const dead = [];
let aiRowEnriched = 0;
const MAX_AI_ROW_ENRICH = 80;

const lines = String(raw).split('\n').filter(l => l.trim());
if (lines.length >= 2) {
  const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/[^a-z_]/g, '_'));

  for (const line of lines.slice(1)) {
    const vals = line.split(',');
    const obj = {};
    headers.forEach((h, i) => obj[h] = (vals[i] || '').trim());

    let inversor = String(obj.inversor || '').trim();
    let bateria = String(obj.bateria || '').trim();
    let cargadorEv = String(obj.cargador_ev || '').trim();
    let compatible = toBool(obj.compatible);

    if ((!inversor || !bateria || !cargadorEv) && ctx.AI_API_KEY && aiRowEnriched < MAX_AI_ROW_ENRICH) {
      const ai = await aiCompleteCompatRow({ inversor, bateria, cargador_ev: cargadorEv, compatible, raw: obj });
      if (ai) {
        inversor = inversor || String(ai.inversor || '').trim();
        bateria = bateria || String(ai.bateria || '').trim();
        cargadorEv = cargadorEv || String(ai.cargador_ev || '').trim();
        if (obj.compatible === undefined || obj.compatible === null || String(obj.compatible).trim() === '') {
          compatible = !!ai.compatible;
        }
        aiRowEnriched += 1;
      }
    }

    if (!inversor || !bateria || !cargadorEv) {
      dead.push({ ...obj, _error: 'Clave compuesta incompleta' });
      continue;
    }

    records.push({
      inversor,
      bateria,
      cargador_ev: cargadorEv,
      compatible
    });
  }
}

